"use client";

import { Save } from "lucide-react";
import { useParams, useRouter } from "next/navigation";
import { useEffect, useState } from "react";

import Layout from "@/components/Layout";
import {
  apiJson,
  errorMessage,
} from "@/lib/client/api";
import { notify } from "@/lib/notify";

type TeacherForm = {
  id?: number;
  employee_id?: string | null;
  first_name?: string | null;
  last_name?: string | null;
  gender?: string | null;
  phone?: string | null;
  email?: string | null;
  qualification?: string | null;
  experience_years?: number | string | null;
  joining_date?: string | null;
  department?: string | null;
  designation?: string | null;
  salary?: number | string | null;
  address?: string | null;
  class_id?: number | string | null;
  section_id?: number | string | null;
  assignment_type?: string | null;
};

const fields: Array<
  keyof TeacherForm
> = [
  "employee_id",
  "first_name",
  "last_name",
  "phone",
  "email",
  "department",
  "designation",
  "qualification",
  "experience_years",
  "salary",
  "address",
];

export default function EditTeacherPage() {
  const params = useParams();
  const router = useRouter();
  const [form, setForm] =
    useState<TeacherForm>({});
  const [classes, setClasses] =
    useState<any[]>([]);
  const [sections, setSections] =
    useState<any[]>([]);
  const [saving, setSaving] =
    useState(false);

  useEffect(() => {
    loadTeacher();
  }, []);

  const loadTeacher = async () => {
    try {
      const [data, roster] =
        await Promise.all([
          apiJson<any>(
            `/api/teachers/${params.id}`
          ),
          apiJson<any>("/api/roster"),
        ]);

      setForm(data.teacher ?? data);
      setClasses(
        Array.isArray(roster.classes)
          ? roster.classes
          : []
      );
      setSections(
        Array.isArray(roster.sections)
          ? roster.sections
          : []
      );
    } catch (error) {
      notify.error(
        errorMessage(
          error,
          "Failed to load teacher"
        )
      );
    }
  };

  const updateTeacher = async () => {
    try {
      setSaving(true);

      await apiJson(
        `/api/teachers/${params.id}`,
        {
          method: "PUT",
          headers: {
            "Content-Type":
              "application/json",
          },
          body: JSON.stringify(form),
        }
      );

      notify.success(
        "Teacher updated"
      );
      router.push("/teachers");
    } catch (error) {
      notify.error(
        errorMessage(
          error,
          "Failed to update teacher"
        )
      );
    } finally {
      setSaving(false);
    }
  };

  const filteredSections =
    sections.filter(
      (section) =>
        !form.class_id ||
        Number(section.class_id) ===
          Number(form.class_id)
    );

  return (
    <Layout>
      <div className="mx-auto max-w-6xl space-y-6">
        <div>
          <h1 className="text-3xl font-black md:text-4xl">
            Edit Teacher
          </h1>
          <p className="mt-1 text-sm text-slate-600">
            Update faculty profile data for the selected school and academic year.
          </p>
        </div>

        <div className="tt-card tt-card-pad">
          <div
            className="
              grid
              gap-4
              md:grid-cols-2
              xl:grid-cols-3
            "
          >
            {fields.map((field) => (
              <label
                key={field}
                className="min-w-0"
              >
                <span className="mb-1 block text-sm font-bold capitalize text-slate-700">
                  {field.replaceAll(
                    "_",
                    " "
                  )}
                </span>
                <input
                  className="input"
                  value={
                    form[field] ?? ""
                  }
                  onChange={(event) =>
                    setForm(
                      (previous) => ({
                        ...previous,
                        [field]:
                          event.target.value,
                      })
                    )
                  }
                />
              </label>
            ))}
            <label className="min-w-0">
              <span className="mb-1 block text-sm font-bold text-slate-700">
                Class Assignment
              </span>
              <select
                className="input"
                value={
                  form.class_id ?? ""
                }
                onChange={(event) =>
                  setForm(
                    (previous) => ({
                      ...previous,
                      class_id:
                        event.target.value,
                      section_id: "",
                    })
                  )
                }
              >
                <option value="">
                  No Class
                </option>
                {classes.map((item) => (
                  <option
                    key={item.id}
                    value={item.id}
                  >
                    {item.class_name}
                  </option>
                ))}
              </select>
            </label>
            <label className="min-w-0">
              <span className="mb-1 block text-sm font-bold text-slate-700">
                Section Assignment
              </span>
              <select
                className="input"
                value={
                  form.section_id ?? ""
                }
                disabled={!form.class_id}
                onChange={(event) =>
                  setForm(
                    (previous) => ({
                      ...previous,
                      section_id:
                        event.target.value,
                    })
                  )
                }
              >
                <option value="">
                  No Section
                </option>
                {filteredSections.map(
                  (item) => (
                    <option
                      key={item.id}
                      value={item.id}
                    >
                      {item.section_name}
                    </option>
                  )
                )}
              </select>
            </label>
            <label className="min-w-0">
              <span className="mb-1 block text-sm font-bold text-slate-700">
                Assignment Type
              </span>
              <select
                className="input"
                value={
                  form.assignment_type ||
                  "CLASS_TEACHER"
                }
                onChange={(event) =>
                  setForm(
                    (previous) => ({
                      ...previous,
                      assignment_type:
                        event.target.value,
                    })
                  )
                }
              >
                <option value="CLASS_TEACHER">
                  Class Teacher
                </option>
                <option value="SUBJECT_TEACHER">
                  Subject Teacher
                </option>
                <option value="MENTOR">
                  Mentor
                </option>
                <option value="SUPERVISOR">
                  Supervisor
                </option>
              </select>
            </label>
          </div>

          <button
            onClick={updateTeacher}
            disabled={saving}
            className="tt-button mt-6 inline-flex items-center gap-2"
          >
            <Save size={17} />
            {saving
              ? "Updating..."
              : "Update Teacher"}
          </button>
        </div>
      </div>
    </Layout>
  );
}
